SELECT login_chk_cnt as "failCnt" FROM msf_user_info WHERE user_id = #{userId}
update msf_user_info set
user_sttus_cd = #{userSttusCd}, access_limit_yn = 'Y', access_limit_dt = now(), chg_dt = now(),
login_chk_cnt = login_chk_cnt + 1 where 1=1 and user_id = #{userId}

update msf_usr_app_info
set last_access_dt = now()
where 1=1
and uuid = #{uuid}
